import Slider from "react-slick";

const HeroSlider = () => {
  const settings = {
    dots: true,
    infinite: true,
    speed: 800,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 3000,
    arrows: false,
  };

  // Make sure slides only contain simple data, not JSX objects
  const slides = [
    {
      id: 1,
      image: "/images/slider1.jpg",
      title: "Limited Time Offer 30% Off",
      subtitle: "Experience Pure Sound – Your Perfect Headphones Awaits!",
      button: "Buy now",
    },
    {
      id: 2,
      image: "/images/slider2.jpeg",
      title: "New Arrivals",
      subtitle: "Step into style with our latest shoe collection",
      button: "Shop now",
    },
    {
      id: 3,
      image: "/images/slider3.jpg",
      title: "Best Deals",
      subtitle: "Grab gadgets at unbeatable prices",
      button: "Explore",
    },
  ];

  return (
    <div style={{ width: "100%", maxWidth: "1200px", margin: "0 auto", marginBottom: "40px" }}>
      <Slider {...settings}>
        {slides.map((slide) => (
          <div key={slide.id}>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                background: "#f9f9f9",
                padding: "40px",
                borderRadius: "12px",
              }}
            >
              {/* Text */}
              <div style={{ flex: 1, paddingRight: "20px" }}>
                <h3 style={{ color: "#ff6600" }}>{slide.title}</h3>
                <h2 style={{ fontSize: "28px", fontWeight: "bold", margin: "10px 0" }}>
                  {slide.subtitle}
                </h2>
                <button
                  style={{
                    padding: "10px 20px",
                    border: "none",
                    borderRadius: "6px",
                    background: "#ff6600",
                    color: "#fff",
                    cursor: "pointer",
                  }}
                >
                  {slide.button}
                </button>
              </div>

              {/* Image */}
              <div style={{ flex: 1, textAlign: "center" }}>
                <img
                  src={slide.image}
                  alt={slide.title}
                  style={{ maxWidth: "100%", height: "250px", objectFit: "contain" }}
                />
              </div>
            </div>
          </div>
        ))}
      </Slider>
    </div>
  );
};

export default HeroSlider;
